var cfg    = $('Set Credentials and Config').first().json;
var serp   = $('Search Google via Serper').first().json;
var news   = $('Fetch News Articles').first().json;
var market = $('Fetch Market Data').first().json;

// --- Web search results ---
var searchResults = [];
try {
  (serp.organic || []).slice(0, 8).forEach(function(r) {
    searchResults.push({
      title:   r.title   || '',
      snippet: r.snippet || '',
      url:     r.link    || '',
      source:  (r.link || '').replace(/https?:\/\/(www\.)?/,'').split('/')[0]
    });
  });
} catch(e) { searchResults = [{ title:'Search unavailable', snippet:'', url:'', source:'' }]; }

// --- News articles ---
var newsArticles = [];
try {
  ((news.articles) || []).slice(0, 8).forEach(function(a) {
    newsArticles.push({
      title:       a.title       || '',
      description: a.description || '',
      source:      (a.source && a.source.name) ? a.source.name : '',
      publishedAt: a.publishedAt || '',
      url:         a.url         || ''
    });
  });
} catch(e) { newsArticles = [{ title:'News unavailable', description:'', source:'', publishedAt:'', url:'' }]; }

// --- Financial / market data ---
var financialData = {};
try {
  if (market && market.Symbol) {
    financialData = {
      symbol:        market.Symbol        || '',
      name:          market.Name          || '',
      sector:        market.Sector        || '',
      industry:      market.Industry      || '',
      marketCap:     market.MarketCapitalization || '',
      peRatio:       market.PERatio       || '',
      eps:           market.EPS           || '',
      revenue:       market.RevenueTTM    || '',
      profitMargin:  market.ProfitMargin  || '',
      week52High:    market['52WeekHigh'] || '',
      week52Low:     market['52WeekLow']  || '',
      description:   (market.Description || '').substring(0, 600)
    };
  } else {
    financialData = { note: 'No ticker provided or financial data unavailable' };
  }
} catch(e) { financialData = { note: 'Financial data parse error' }; }

// --- Build context summary for AI ---
var searchContext = searchResults.map(function(r, i) {
  return (i+1) + '. ' + r.title + '\n   ' + r.snippet + '\n   Source: ' + r.source;
}).join('\n\n');

var newsContext = newsArticles.map(function(a, i) {
  return (i+1) + '. [' + a.source + '] ' + a.title + ' (' + (a.publishedAt||'').substring(0,10) + ')\n   ' + a.description;
}).join('\n\n');

var financialContext = JSON.stringify(financialData, null, 2);

return [{ json: {
  reportId:         cfg.reportId,
  topic:            cfg.topic,
  company:          cfg.company,
  ticker:           cfg.ticker,
  industry:         cfg.industry,
  reportType:       cfg.reportType,
  recipientEmail:   cfg.recipientEmail,
  requestedAt:      cfg.requestedAt,
  ANTHROPIC_KEY:    cfg.ANTHROPIC_KEY,
  SENDGRID_KEY:     cfg.SENDGRID_KEY,
  SLACK_WEBHOOK:    cfg.SLACK_WEBHOOK,
  DRIVE_FOLDER_ID:  cfg.DRIVE_FOLDER_ID,
  SHEET_ID:         cfg.SHEET_ID,
  searchResults:    searchResults,
  newsArticles:     newsArticles,
  financialData:    financialData,
  searchContext:    searchContext,
  newsContext:      newsContext,
  financialContext: financialContext,
  totalSources:     searchResults.length + newsArticles.length,
  dataCollectedAt:  new Date().toISOString()
}}];

var raw  = $('Claude Pass 1 Research Synthesis').first().json;
var prev = $('Merge and Clean Data').first().json;

var pass1Text = '';
try {
  if (raw.content && Array.isArray(raw.content)) {
    pass1Text = raw.content.map(function(b){ return b.text || ''; }).join('\n');
  } else {
    pass1Text = JSON.stringify(raw);
  }
} catch(e) { pass1Text = 'Pass 1 error: ' + e.message; }

var result = JSON.parse(JSON.stringify(prev));
result.pass1Output    = pass1Text;
result.pass1Tokens    = (raw.usage && raw.usage.output_tokens) ? raw.usage.output_tokens : 0;
result.pass1CompletedAt = new Date().toISOString();
return [{ json: result }];

var raw  = $('Claude Pass 2 Strategic SWOT').first().json;
var prev = $('Extract Pass 1 Output').first().json;

var pass2Text = '';
try {
  if (raw.content && Array.isArray(raw.content)) {
    pass2Text = raw.content.map(function(b){ return b.text || ''; }).join('\n');
  } else {
    pass2Text = JSON.stringify(raw);
  }
} catch(e) { pass2Text = 'Pass 2 error: ' + e.message; }

var result = JSON.parse(JSON.stringify(prev));
result.pass2Output      = pass2Text;
result.pass2Tokens      = (raw.usage && raw.usage.output_tokens) ? raw.usage.output_tokens : 0;
result.pass2CompletedAt = new Date().toISOString();
return [{ json: result }];

var raw  = $('Claude Pass 3 Write Final Report').first().json;
var prev = $('Extract Pass 2 Output').first().json;

var reportMarkdown = '';
try {
  if (raw.content && Array.isArray(raw.content)) {
    reportMarkdown = raw.content.map(function(b){ return b.text || ''; }).join('\n');
  } else {
    reportMarkdown = JSON.stringify(raw);
  }
} catch(e) { reportMarkdown = 'Report generation error: ' + e.message; }

// Extract metadata lines
var reportTitle   = prev.topic + ' — Business Report';
var reportSummary = '';
var reportScore   = 80;
try {
  var titleMatch   = reportMarkdown.match(/END_REPORT_TITLE:\s*(.+)/);
  if (titleMatch)   reportTitle = titleMatch[1].trim();
  var summaryMatch = reportMarkdown.match(/END_REPORT_SUMMARY:\s*(.+)/);
  if (summaryMatch) reportSummary = summaryMatch[1].trim();
  var scoreMatch   = reportMarkdown.match(/END_REPORT_SCORE:\s*(\d+)/);
  if (scoreMatch)   reportScore = parseInt(scoreMatch[1]);
} catch(e) {}

// Strip the trailing metadata lines from the body
var cleanReport = reportMarkdown
  .replace(/END_REPORT_TITLE:.+/g, '')
  .replace(/END_REPORT_SUMMARY:.+/g, '')
  .replace(/END_REPORT_SCORE:.+/g, '')
  .trim();

var totalTokens = (prev.pass1Tokens || 0) + (prev.pass2Tokens || 0) + ((raw.usage && raw.usage.output_tokens) ? raw.usage.output_tokens : 0);

var result = JSON.parse(JSON.stringify(prev));
result.reportMarkdown  = cleanReport;
result.reportTitle     = reportTitle;
result.reportSummary   = reportSummary;
result.reportScore     = reportScore;
result.totalTokens     = totalTokens;
result.totalSources    = prev.totalSources || 0;
result.completedAt     = new Date().toISOString();
result.reportPreview   = cleanReport.substring(0, 800);

return [{ json: result }];
